const os = require('os');
const total = os.totalmem();
const free = os.freemem();
const used = total - free;
const percentUsed = (used / total) * 100;
console.log(`Mémoire utilisée: ${percentUsed.toFixed(2)}%`);

function generateReport() {
  const os = require('os');
  const totalMem = (os.totalmem() / (1024 * 1024)).toFixed(0);
  const usedPercent = ((os.totalmem() - os.freemem()) / os.totalmem() * 100).toFixed(1);
  return `=== DIAGNOSTIC SYSTÈME ===
Plateforme: ${os.platform()}
CPUs: ${os.cpus().length} cœurs logiques
Mémoire totale: ${totalMem} Mo
Mémoire utilisée: ${usedPercent}%
Dossier temporaire: ${os.tmpdir()}`;
}
